#include <stdio.h>
#include <stdlib.h>

int main() {
    int N;
    scanf("%d", &N);
    int* arr = (int*) malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        scanf("%d", &arr[i]);
    }
    int altDepth = 0;
    int maxSeq1 = 0;
    int maxSeq2 = 0;
    int* stack = (int*) malloc(N * sizeof(int));
    int top = -1;
    for (int i = 0; i < N; i++) {
        if (arr[i] == 1 || arr[i] == 3) {
            stack[++top] = arr[i];
        } else {
            int opening = stack[top--];
            if (opening == 1 && arr[i] == 2) {
                maxSeq1 = max(maxSeq1, i - top);
            } else if (opening == 3 && arr[i] == 4) {
                maxSeq2 = max(maxSeq2, i - top);
            }
            if (top > 0 && stack[top - 1] != opening) {
                altDepth = max(altDepth, top);
            }
        }
    }
    printf("%d %d %d\n", altDepth, maxSeq1, maxSeq2);
    free(arr);
    free(stack);
    return 0;
}

