#include <iostream>
#include <stack>
using namespace std;

int main() {
    int N;
    cin >> N;
    int* arr = new int[N];
    for (int i = 0; i < N; i++) {
        cin >> arr[i];
    }
    int altDepth = 0;
    int maxSeq1 = 0;
    int maxSeq2 = 0;
    stack<int> s;
    for (int i = 0; i < N; i++) {
        if (arr[i] == 1 || arr[i] == 3) {
            s.push(arr[i]);
        } else {
            int opening = s.top();
            s.pop();
            if (opening == 1 && arr[i] == 2) {
                maxSeq1 = max(maxSeq1, i - (int)s.size());
            } else if (opening == 3 && arr[i] == 4) {
                maxSeq2 = max(maxSeq2, i - (int)s.size());
            }
            if (!s.empty() && s.top() != opening) {
                altDepth = max(altDepth, (int)s.size() + 1);
            }
        }
    }
    cout << altDepth << " " << maxSeq1 << " " << maxSeq2 << endl;
    delete[] arr;
    return 0;
}

