import java.util.Stack;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int[] arr = new int[N];
        for (int i = 0; i < N; i++) {
            arr[i] = sc.nextInt();
        }
        int altDepth = 0;
        int maxSeq1 = 0;
        int maxSeq2 = 0;
        Stack<Integer> s = new Stack<>();
        for (int i = 0; i < N; i++) {
            if (arr[i] == 1 || arr[i] == 3) {
                s.push(arr[i]);
            } else {
                int opening = s.pop();
                if (opening == 1 && arr[i] == 2) {
                    maxSeq1 = Math.max(maxSeq1, i - s.size());
                } else if (opening == 3 && arr[i] == 4) {
                    maxSeq2 = Math.max(maxSeq2, i - s.size());
                }
                if (!s.isEmpty() && s.peek() != opening) {
                    altDepth = Math.max(altDepth, s.size() + 1);
                }
            }
        }
        System.out.println(altDepth + " " + maxSeq1 + " " + maxSeq2);
    }
}

